-- ============================================================
-- V22__normalize_book_isbns.sql
-- Normalize demo book ISBNs to standard ISBN-13 values.
--
-- This migration updates by book id because some copied old ISBN values may
-- have lost a zero while being exported from a sheet. It still records the
-- expected old ISBN for review/precheck output.
-- ============================================================
--
-- Note:
-- - This does not touch book_copies. Physical copies are linked by book_id and
--   keep their own barcodes.
-- - The provided value for book 3179 was `978136049112`, which is 12 digits.
--   This script uses the ISBN-13 value `9781736049112`.
CREATE TEMP TABLE tmp_book_isbn_updates (
    book_id BIGINT PRIMARY KEY,
    old_isbn VARCHAR(20) NOT NULL,
    new_isbn VARCHAR(20) NOT NULL
) ON COMMIT DROP;


-- Precheck 1: rows missing or old ISBN no longer matches.
-- Old ISBN mismatch is informational only; update is driven by book_id.
SELECT
    'MISSING_OR_OLD_ISBN_MISMATCH' AS issue,
    t.book_id,
    b.title,
    t.old_isbn AS expected_old_isbn,
    b.isbn AS current_isbn,
    t.new_isbn
FROM tmp_book_isbn_updates t
LEFT JOIN books b ON b.id = t.book_id
WHERE b.id IS NULL OR b.isbn <> t.old_isbn
ORDER BY t.book_id;

-- Precheck 2: new ISBN already exists on another book.
SELECT
    'NEW_ISBN_ALREADY_EXISTS_ON_OTHER_BOOK' AS issue,
    t.book_id AS source_book_id,
    t.new_isbn,
    b.id AS conflicting_book_id,
    b.title AS conflicting_title
FROM tmp_book_isbn_updates t
JOIN books b ON LOWER(b.isbn) = LOWER(t.new_isbn)
            AND b.id <> t.book_id
ORDER BY t.book_id;

-- Precheck 3: duplicate target ISBN inside this update list.
SELECT
    'DUPLICATE_NEW_ISBN_IN_UPDATE_LIST' AS issue,
    new_isbn,
    COUNT(*) AS total
FROM tmp_book_isbn_updates
GROUP BY LOWER(new_isbn), new_isbn
HAVING COUNT(*) > 1
ORDER BY new_isbn;

-- Precheck 4: target ISBNs that are not 13 digits.
SELECT
    'NEW_ISBN_NOT_13_DIGITS' AS issue,
    book_id,
    new_isbn
FROM tmp_book_isbn_updates
WHERE new_isbn !~ '^[0-9]{13}$'
ORDER BY book_id;

-- Abort if a target ISBN already belongs to another book.
DO $$
BEGIN
    IF EXISTS (
        SELECT 1
        FROM tmp_book_isbn_updates t
        LEFT JOIN books b ON b.id = t.book_id
        WHERE b.id IS NULL
    ) THEN
        RAISE EXCEPTION 'Some book ids do not exist. Check precheck 1 output.';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM tmp_book_isbn_updates t
        JOIN books b ON LOWER(b.isbn) = LOWER(t.new_isbn)
                    AND b.id <> t.book_id
    ) THEN
        RAISE EXCEPTION 'New ISBN already exists on another book. Check precheck 2 output.';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM (
            SELECT LOWER(new_isbn)
            FROM tmp_book_isbn_updates
            GROUP BY LOWER(new_isbn)
            HAVING COUNT(*) > 1
        ) duplicated
    ) THEN
        RAISE EXCEPTION 'Duplicate new ISBN in update list. Check precheck 3 output.';
    END IF;

    IF EXISTS (
        SELECT 1
        FROM tmp_book_isbn_updates
        WHERE new_isbn !~ '^[0-9]{13}$'
    ) THEN
        RAISE EXCEPTION 'Some target ISBNs are not 13 digits. Check precheck 4 output.';
    END IF;
END $$;

-- Update by book id.
UPDATE books b
SET isbn = t.new_isbn,
    updated_at = NOW()
FROM tmp_book_isbn_updates t
WHERE b.id = t.book_id;

-- Verification: should equal total rows in tmp_book_isbn_updates.
SELECT COUNT(*) AS books_updated_to_target_isbn
FROM tmp_book_isbn_updates t
JOIN books b ON b.id = t.book_id
            AND b.isbn = t.new_isbn;

-- Verification: should return zero rows.
SELECT
    t.book_id,
    b.title,
    t.new_isbn AS expected_new_isbn,
    b.isbn AS current_isbn
FROM tmp_book_isbn_updates t
JOIN books b ON b.id = t.book_id
WHERE b.isbn <> t.new_isbn
ORDER BY t.book_id;
